function TaskReportConfig:initConfig(configs)
    for _, config in pairs(configs) do
        local data = {}
        data.Id = tonumber(config.Id)
        data.Name = config.Name
        data.TaskIds = StringUtil.split(config.TaskIds, "#"),
        table.insert(self.TaskReports, data)
    end
end

function TaskReportConfig:getNameByTaskId(taskId)

    for _, Report in pairs(self.TaskReports) do
        for _, Id in pairs(Report.TaskIds) do
            if tostring(Id) == tostring(taskId) then
                return Report.Name
            end
        end
    end
